INSERT INTO `archetypes` (`id`, `name`, `description`, `speaking_style`, `vocabulary_examples`, `typo_rate`, `emoji_rate`, `response_delay_min`, `response_delay_max`, `avatar_seed`, `created_at`) VALUES
(1, 'Mae de Familia', 'Mulher de 35-50 anos, pratica, carinhosa', 'Fala de forma carinhosa e pratica. Usa gente, meninas. Conta experiencias reais com filhos e marido.', 'Gente, to adorando! / meninas me ajudem / fiz pra toda familia', 15, 35, 5, 30, 'mae1', '2026-03-01 13:29:07'),
(2, 'Nerd Fitness', 'Homem de 25-35 anos, obcecado com dados e macros', 'Fala com precisao cientifica. Cita estudos. Gosta de numeros e percentuais.', 'De acordo com um estudo / meu percentual de gordura / a ciencia mostra que', 5, 10, 8, 40, 'nerd1', '2026-03-01 13:29:07'),
(3, 'Mano da Quebrada', 'Jovem de 18-28 anos, girias, informal, entusiasmado', 'Usa mano, cara, demais. Frases curtas. Muitos pontos de exclamacao.', 'mano que resultado!! / cara to chocado / funcionou demais', 25, 45, 2, 15, 'mano1', '2026-03-01 13:29:07'),
(4, 'Nutricionista', 'Profissional da saude, 30-45 anos, didatica', 'Linguagem tecnica mas acessivel. Cuida para nao dar diagnostico.', 'Do ponto de vista nutricional / as evidencias indicam / consulte um profissional', 3, 15, 10, 45, 'nutri1', '2026-03-01 13:29:07'),
(5, 'Vendedor de Rua', 'Pessoa animada, persuasiva, 28-45 anos', 'Entusiasta, muitas exclamacoes. Sempre descobriu o segredo de algo.', 'Descobri o segredo! / vale demais a pena / to te contando isso porque', 20, 40, 3, 20, 'vend1', '2026-03-01 13:29:07'),
(6, 'Advogado', 'Profissional exigente, cetico, 35-50 anos', 'Questiona antes de aceitar. Analitico. Usa todavia, entretanto, cabe ressaltar.', 'Quais sao as evidencias? / cabe ressaltar que / todavia os resultados mostram', 5, 5, 15, 60, 'adv1', '2026-03-01 13:29:07');
INSERT INTO `blocks` (`id`, `room_id`, `name`, `topic`, `status`, `start_at`, `created_at`, `loop_infinite`, `is_tips_block`) VALUES
(1, 1, 'Dicas dos Nutricionistas', 'Dicas técnicas dos nutricionistas administradores. Loop infinito, intercalado randomicamente.', 'running', NULL, '2026-03-03 09:41:47', 1, 1),
(2, 1, 'Resultados e Transformações', 'Membros compartilhando resultados específicos: kg perdidos, medidas, como o corpo mudou', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(3, 1, 'Dúvidas de Praticantes', 'Dúvidas de quem já usa: como adaptar em situações específicas, metabolismo, condições de saúde', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(4, 1, 'Egípcio vs Outras Dietas', 'Comparação entre o método e low carb, jejum, mediterrânea — feita por quem experimentou ambos', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(5, 1, 'Dicas Práticas do Protocolo', 'Hacks e dicas de membros experientes: café da manhã, marmita, sequência alimentar', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(6, 1, 'Valeu o Investimento?', 'Membros falando sobre custo vs resultado. Comparações com o que gastavam antes', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(7, 1, 'Primeiros 7 Dias — Surpresa Total', 'Relatos de quem está na primeira semana e ficou chocado com a velocidade do resultado', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(8, 1, 'Quem Tentou Tudo e Finalmente Conseguiu', 'Histórias de múltiplas tentativas fracassadas e como o protocolo foi diferente', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(9, 1, 'Homens Sem Camisa Novamente', 'Homens relatando a sensação de voltar à praia, piscina, tirar a camisa com confiança', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(10, 1, 'Mulheres e o Biquíni de Volta', 'Mulheres que voltaram a usar o biquíni guardado. Autoestima, roupas antigas, fotos', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(11, 1, 'Casais Que Começaram Juntos', 'Casais no protocolo. Resultados dos dois, apoio mútuo, quem está na frente', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(12, 1, 'Mães e a Família Toda', 'Mães que adaptaram o protocolo para a família inteira. Como fizeram, o que acharam', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(13, 1, 'O Inchaço Que Sumiu em Dias', 'Foco na desinflamação rápida. Roupas que voltaram a servir antes mesmo de perder muito peso', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(14, 1, 'Metabolismo Lento — Acabou a Desculpa', 'Pessoas que tinham essa crença e viram o protocolo funcionar de qualquer jeito', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(15, 1, 'Sem Academia, Sem Suplemento, Sem Fome', 'O diferencial: nenhum dos três. Resultado puro de alimentação na ordem certa', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(16, 1, 'Antes Eu Sofria de Fome, Agora Como', 'Contraste com dietas restritivas anteriores. A liberdade do protocolo vs o sofrimento de antes', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(17, 1, 'Quando Todo Mundo Começa a Perguntar', 'O momento em que colegas, vizinhos e família notam e perguntam o segredo', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(18, 1, 'R$29,90 — O Investimento Que Valeu Tudo', 'Foco no preço acessível e no contraste com outros métodos caros e sem resultado', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(19, 1, 'Acesso Vitalício — Para Sempre', 'Membros falando sobre ter acesso pra vida toda, consultar quando quiser, indicar amigos', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(20, 1, 'Acima de 50 — Funciona Igual', 'Pessoas mais velhas que acreditavam que a idade era obstáculo. Foram surpreendidas', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(21, 1, 'Protocolo Fora de Casa — Restaurante e Viagem', 'Como membros mantêm o protocolo comendo fora, viajando, em festas', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(22, 1, 'Resultados Extremos — Acima de 15kg', 'Foco nos casos de maior perda. Números, prazos, como fizeram', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
