(27, 1, 'Roupas Antigas de Volta', 'O momento emocional de vestir uma peça guardada. Calças, vestidos, biquínis', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
(28, 1, 'Virei Promotor — Já Indiquei 5 ou Mais', 'Membros que se tornaram divulgadores orgânicos e os resultados de quem indicaram', 'running', NULL, '2026-03-03 09:41:47', 0, 0),
