INSERT INTO `timeline_messages` (`id`, `block_id`, `bot_id`, `archetype_id`, `resolved_name`, `message_type`, `content`, `reply_to_id`, `sequence_order`, `delay_after_prev`, `posted_at`, `created_at`) VALUES
(67, 1, NULL, 4, NULL, 'tip', 'Dica técnica: nos primeiros dias mais idas ao banheiro são normais. O corpo está eliminando retenção hídrica acumulada.', NULL, 1, 62, '2026-03-03 07:31:30', '2026-03-03 09:41:47'),
(68, 1, NULL, 4, NULL, 'tip', 'Do ponto de vista clínico: a glicemia em jejum pode cair 15-20 pontos em 30 dias só com mudança na sequência alimentar.', NULL, 2, 71, '2026-03-03 07:32:25', '2026-03-03 09:41:47'),
(69, 1, NULL, 4, NULL, 'tip', 'Dica do dia: beber 200ml de água 15-20min antes das refeições potencializa o efeito de saciedade.', NULL, 3, 55, '2026-03-03 07:34:33', '2026-03-03 09:41:47'),
(70, 1, NULL, 4, NULL, 'tip', 'A lógica da sequência alimentar do protocolo é consistente com as últimas diretrizes nutricionais internacionais.', NULL, 4, 60, NULL, '2026-03-03 09:41:47'),
(71, 1, NULL, 4, NULL, 'tip', 'Lembrete técnico: proteínas no café da manhã não precisam ser complexas. Ovo já é suficiente e eficiente.', NULL, 5, 54, NULL, '2026-03-03 09:41:47'),
(72, 1, NULL, 4, NULL, 'tip', 'Dica para quem tem refluxo: comer mais devagar e mastigar bem reduz os sintomas. O protocolo já incentiva isso.', NULL, 6, 44, NULL, '2026-03-03 09:41:47'),
(73, 1, NULL, 4, NULL, 'tip', 'Do ponto de vista nutricional: diversidade de vegetais nas refeições potencializa a microbiota intestinal e o resultado.', NULL, 7, 67, NULL, '2026-03-03 09:41:47'),
